#include<bits/stdc++.h>
using namespace std;
int k,m1,m2;
int sum1[100005],sum2[100005];
pair<int,int>a[100005],b[100005];
void solve1()
{
	priority_queue<int,vector<int>,greater<int> >q;
	priority_queue<pair<int,int>, vector<pair<int,int> >,greater<pair<int,int> > >t;
	for(int i = 1; i <= m1; i++)q.push(i);
	for(int i = 1; i <= m1; i++){
		while(!t.empty() && t.top().first < a[i].first){
			q.push(t.top().second);
			t.pop();
		}
		if(!q.empty()){
			t.push({a[i].second,q.top()});
			sum1[q.top()]++;
			q.pop();
		}
	}
}
void solve2()
{
	priority_queue<int,vector<int>,greater<int> >q;
	priority_queue<pair<int,int>, vector<pair<int,int> >,greater<pair<int,int> > >t;
	for(int i = 1; i <= m2; i++)q.push(i);
	for(int i = 1; i <= m2; i++){
		while(!t.empty() && t.top().first < b[i].first){
			q.push(t.top().second);
			t.pop();
		}
		if(!q.empty()){
			t.push({b[i].second,q.top()});
			sum2[q.top()]++;
			q.pop();
		}
	}
}
int main()
{
//	ios::sync_with_stdio(false);
//	cin.tie(0);
	cin>>k>>m1>>m2;
	for(int i = 1; i <= m1; i++)cin >> a[i].first >> a[i].second;
	for(int i = 1; i <= m2; i++)cin >> b[i].first >> b[i].second;
//	cout<<0;
	sort(a+1,a+1+m1);
	sort(b+1,b+m2+1);
//	cout<<1;
	solve1(),solve2();
//	cout<<2;
	int maxi = 0;
	for(int i = 1; i <= k; i++){
		sum1[i] = sum1[i-1] + sum1[i];
		sum2[i] = sum2[i-1] + sum2[i];
	}
	for(int i = 0; i <= k; i++){
		maxi = max(maxi,sum1[i] + sum2[k - i]);
	}
//	cout<<3;
	cout << maxi;

